import React, { useState, useEffect } from 'react';
import { Section } from './types';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './components/sections/Home';
import Research from './components/sections/Research';
import Publications from './components/sections/Publications';
import Projects from './components/sections/Projects';
import Teaching from './components/sections/Teaching';
import CV from './components/sections/CV';
import Contact from './components/sections/Contact';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<Section>(Section.Home);

  // Simple hash-based "routing" within the SPA
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '') as Section;
      if (Object.values(Section).includes(hash)) {
        setActiveSection(hash);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const renderSection = () => {
    switch (activeSection) {
      case Section.Home: return <Home />;
      case Section.Research: return <Research />;
      case Section.Publications: return <Publications />;
      case Section.Projects: return <Projects />;
      case Section.Teaching: return <Teaching />;
      case Section.CV: return <CV />;
      case Section.Contact: return <Contact />;
      default: return <Home />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-blue-100">
      <Navbar activeSection={activeSection} />

      <main className="flex-grow pt-24 pb-12">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="bg-white shadow-sm rounded-xl overflow-hidden border border-slate-100 transition-all duration-300">
            {renderSection()}
          </div>
        </div>
      </main>

      <Footer />
    </div>
  );
};

export default App;

